mapper.select:
select his_inpatient_charge_id as hisChargeId, row_fingerprint as rowFingerprint
from his_inpatient_charge_mirror
where tenant_id = #{tenantId}
and his_inpatient_charge_id in
#{hid}

select 'INPATIENT' as visitType, patient_name as patientName, inpatient_no as visitNo,
       ifnull(dept_name,'') as deptName, count(*) as lineCount, ifnull(sum(total_amount),0) as sumAmount
from his_inpatient_charge_mirror
where tenant_id = #{tenantId}
and left(replace(ifnull(charge_date,''),'/','-'),10) >= #{beginChargeDate}
and left(replace(ifnull(charge_date,''),'/','-'),10) <= #{endChargeDate}
group by patient_name, inpatient_no, ifnull(dept_name,'')
order by sumAmount desc

select count(*) from his_inpatient_charge_mirror
where tenant_id = #{tenantId} and fetch_batch_id = #{fetchBatchId}
and process_status = 'CONSUMED'

mapper.update:
update his_inpatient_charge_mirror set process_status = #{processStatus}, update_time = now()
where tenant_id = #{tenantId}
and id in
#{rid}
